"use client";

import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from "@/components/ui/card";
import { useState } from "react";
import { useRouter } from "next/navigation";

export default function LoginPage() {
    const [userId, setUserId] = useState("");
    const [isLoading, setIsLoading] = useState(false);
    const router = useRouter();

    const handleLogin = async () => {
        if (!userId) return;
        setIsLoading(true);

        try {
            const response = await fetch(`http://localhost:8080/api/portfolios/user/${userId}`);

            if (response.ok) {
                const portfolios = await response.json();

                if (portfolios && portfolios.length > 0) {
                    // Login successful
                    const portfolio = portfolios[0]; // Take the first portfolio

                    localStorage.setItem("finsight_userid", userId);
                    localStorage.setItem("finsight_portfolio_id", portfolio.id);
                    localStorage.setItem("finsight_username", portfolio.name);

                    router.push("/dashboard");
                } else {
                    alert("User ID not found. Please check your credentials.");
                }
            } else {
                alert("Login failed. Backend issue?");
            }
        } catch (error) {
            console.error("Login error:", error);
            alert("Connection error. Is the backend running?");
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="flex min-h-screen items-center justify-center p-4">
            <Card className="glass w-full max-w-md border-none text-white overflow-hidden">
                <CardHeader className="space-y-1 text-center py-8 bg-white/[0.02]">
                    <CardTitle className="text-3xl font-bold tracking-tighter">Welcome back</CardTitle>
                    <CardDescription className="text-slate-400">
                        Enter your credentials to access your terminal
                    </CardDescription>
                </CardHeader>
                <CardContent className="space-y-4 pt-8">
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-slate-300">User ID</label>
                        <Input
                            type="text"
                            placeholder="0000-0000-0000-0000"
                            className="bg-black/20 border-white/10 text-white focus:ring-slate-400"
                            value={userId}
                            onChange={(e) => setUserId(e.target.value)}
                        />
                    </div>
                    <Button
                        className="w-full bg-white text-black hover:bg-slate-200 transition-colors font-bold"
                        onClick={handleLogin}
                        disabled={isLoading}
                    >
                        {isLoading ? "ACCESSING..." : "ACCOUNT ACCESS"}
                    </Button>
                </CardContent>
                <CardFooter className="flex flex-col gap-4 pb-8">
                    <div className="text-sm text-slate-500 text-center">
                        Don't have an account?{" "}
                        <Link href="/register" className="text-white hover:underline transition-all">
                            Register now
                        </Link>
                    </div>
                </CardFooter>
            </Card>
        </div>
    );
}